// --- Sync Manager (higher-level orchestration) ---

class SyncManager {
  final ApiClient _apiClient;
  DateTime? _lastSyncedAt;
  bool _isSyncing = false;
  Timer? _periodicSyncTimer;

  // Callbacks
  final Future<List<SyncData>> Function()? getLocalChanges;
  final Future<void> Function(List<Map<String, dynamic>>)? applyRemoteChanges;
  final Future<void> Function(DateTime)? onSyncComplete;

  SyncManager({
    required ApiClient apiClient,
    DateTime? lastSyncedAt,
    this.getLocalChanges,
    this.applyRemoteChanges,
    this.onSyncComplete,
  })  : _apiClient = apiClient,
        _lastSyncedAt = lastSyncedAt;

  bool get isSyncing => _isSyncing;
  DateTime? get lastSyncedAt => _lastSyncedAt;

  Future<SyncResult?> sync() async {
    if (_isSyncing) return null;
    if (!_apiClient.isAuthenticated) return null;

    _isSyncing = true;

    try {
      // 1. Get local changes
      final localChanges = await getLocalChanges?.call() ?? [];

      // 2. Push local changes and get result
      final result = await _apiClient.syncData(
        items: localChanges,
        lastSyncedAt: _lastSyncedAt,
      );

      // 3. Fetch remote updates
      final since = _lastSyncedAt ?? DateTime.fromMillisecondsSinceEpoch(0);
      final remoteUpdates = await _apiClient.fetchUpdates(since: since);

      // 4. Apply remote changes locally
      if (remoteUpdates.isNotEmpty) {
        await applyRemoteChanges?.call(remoteUpdates);
      }

      // 5. Update last synced timestamp
      _lastSyncedAt = result.syncedAt;
      await onSyncComplete?.call(result.syncedAt);

      return result;
    } catch (e) {
      rethrow;
    } finally {
      _isSyncing = false;
    }
  }

  void startPeriodicSync({Duration interval = const Duration(minutes: 5)}) {
    stopPeriodicSync();
    _periodicSyncTimer = Timer.periodic(interval, (_) => sync());
  }

  void stopPeriodicSync() {
    _periodicSyncTimer?.cancel();
    _periodicSyncTimer = null;
  }

  void dispose() {
    stopPeriodicSync();
  }
}

// --- Example Usage / Main ---

Future<void> main() async {
  // Create the API client
  final apiClient = ApiClient(
    onTokenChanged: (token) async {
      // In a real app, persist token to secure storage
      if (token != null) {
        print('Token saved: ${token.accessToken.substring(0, 10)}...');
      } else {
        print('Token cleared');
      }
    },
  );

  try {
    // 1. Authentication
    print('--- Logging in ---');
    final token = await apiClient.login(
      email: 'user@example.com',
      password: 'securePassword123',
    );
    print('Logged in. Token expires at: ${token.expiresAt}');

    // 2. Fetch user profile
    print('\n--- Fetching profile ---');
    final profile = await apiClient.getProfile();
    print('Hello, ${profile.name} (${profile.email})');

    // 3. Update profile
    print('\n--- Updating profile ---');
    final updatedProfile = await apiClient.updateProfile(
      name: 'Updated Name',
    );
    print('Profile updated: ${updatedProfile.name}');

    // 4. Data synchronization
    print('\n--- Syncing data ---');
    final syncManager = SyncManager(
      apiClient: apiClient,
      getLocalChanges: () async {
        // Return local changes to push
        return [
          SyncData(
            type: 'note',
            data: {'id': '1', 'title': 'My Note', 'content': 'Hello world'},
            updatedAt: DateTime.now(),
          ),
          SyncData(
            type: 'task',
            data: {'id': '2', 'title': 'Buy groceries', 'done': false},
            updatedAt: DateTime.now(),
          ),
        ];
      },
      applyRemoteChanges: (changes) async {
        print('Applying ${changes.length} remote changes');
        for (final change in changes) {
          print('  - ${change['type']}: ${change['id']}');
        }
      },
      onSyncComplete: (syncedAt) async {
        print('Sync completed at: $syncedAt');
      },
    );

    final syncResult = await syncManager.sync();
    if (syncResult != null) {
      print('Synced ${syncResult.itemsSynced} items');
      if (syncResult.errors.isNotEmpty) {
        print('Sync errors: ${syncResult.errors.join(', ')}');
      }
    }

    // 5. Start periodic sync
    syncManager.startPeriodicSync(interval: const Duration(minutes: 5));

    // 6. Check sync status
    print('\n--- Sync Status ---');
    final status = await apiClient.getSyncStatus();
    print('Sync status: $status');

    // Cleanup
    syncManager.dispose();

    // 7. Logout
    print('\n--- Logging out ---');
    await apiClient.logout();
    print('Logged out successfully');
  } on AuthenticationException catch (e) {
    print('Auth error: $e');
  } on ApiException catch (e) {
    print('API error: $e');
  } on NetworkException catch (e) {
    print('Network error: $e');
  } catch (e) {
    print('Unexpected error: $e');
  } finally {
    apiClient.dispose();
  }
}